import React from 'react';
import { NavLink, Outlet } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';

const links = [
  { to: '/admin', end: true, label: 'Dashboard' },
  { to: '/admin/products', label: 'Products' },
  { to: '/admin/products/new', label: 'New product' },
  { to: '/admin/orders', label: 'Orders' },
  { to: '/admin/categories', label: 'Categories' },
  { to: '/admin/customers', label: 'Customers' },
  { to: '/admin/coupons', label: 'Coupons' },
  { to: '/admin/analytics', label: 'Analytics' }
];

export default function AdminLayout() {
  return (
    <>
      <Helmet>
        <title>Admin | Nova Shop</title>
      </Helmet>
      <div
        className="admin-layout container"
        style={{ padding: '2rem 1rem 4rem', display: 'grid', gap: '1.5rem' }}
      >
        <header className="page-header" style={{ marginBottom: 0 }}>
          <h1>Admin</h1>
        </header>
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'minmax(160px, 200px) 1fr',
            gap: '1.5rem',
            alignItems: 'start'
          }}
          className="admin-layout__grid"
        >
          <nav aria-label="Admin">
            <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
              {links.map(({ to, end, label }) => (
                <li key={to} style={{ marginBottom: '0.35rem' }}>
                  <NavLink
                    to={to}
                    end={end}
                    className={({ isActive }) =>
                      isActive ? 'btn btn-primary btn-sm btn-full' : 'btn btn-outline btn-sm btn-full'
                    }
                    style={{ justifyContent: 'center', fontSize: '0.8rem' }}
                  >
                    {label}
                  </NavLink>
                </li>
              ))}
            </ul>
          </nav>
          <div className="admin-outlet">
            <Outlet />
          </div>
        </div>
      </div>
    </>
  );
}
